function i(e){if(!e)return"—";const t=new Date(e);return`${t.getUTCMonth()+1}/${t.getUTCDate()}/${t.getUTCFullYear()}`}function l(e){return e==null?"days-cell--positive":e<0?"days-cell--expired":e<=60?"days-cell--warning":"days-cell--positive"}function o(e){const t=new Date(e+"T00:00:00"),n=new Date(t);n.setDate(t.getDate()+6);const r=a=>a.toLocaleDateString("en-US",{month:"short",day:"numeric"});return`${r(t)} – ${r(n)}, ${t.getFullYear()}`}export{o as a,l as d,i as f};
